. "$PSScriptRoot\..\Common.ps1"
try{ $p='HKLM:\SYSTEM\CurrentControlSet\Services\LanmanServer\Parameters'; $v=Get-ItemProperty -Path $p -Name AutoShareWks -ErrorAction SilentlyContinue; $shares=Get-SmbShare -ErrorAction SilentlyContinue|Where-Object {$_.Name -match '^[A-Z]\$$|^ADMIN\$$|^IPC\$$'}|Select Name,Path,Description; New-Result -Step '03_DisableAdminShares' -Enabled ($v.AutoShareWks -eq 0) -Status '检查完成；AutoShareWks=0 可持久禁止 C$/D$ 等盘符管理共享' -Evidence @{AutoShareWks=$v.AutoShareWks; Shares=$shares} }catch{ New-Result -Step '03_DisableAdminShares' -Success $false -Status '检查失败' -ErrorMessage $_.Exception.Message }